import React from 'react';

const ExpiryList = ({ rooms = [] }) => {
    const allProducts = rooms.flatMap(room =>
        room.inventory.map(item => ({
            ...item,
            roomId: room.id,
            floor: room.floor
        }))
    );

    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const ninetyDays = new Date(today.getTime() + 90 * 24 * 60 * 60 * 1000);

    const reportItems = allProducts
        .filter(item => item.expiry && new Date(item.expiry) <= ninetyDays)
        .sort((a, b) => new Date(a.expiry) - new Date(b.expiry));

    return (
        <div className="page-content">
            <h2 className="page-title">Контроль сроков (90 дней)</h2>
            <div className="expiry-table-container">
                <table className="expiry-table">
                    <thead>
                    <tr>
                        <th>Номер</th>
                        <th>Товар</th>
                        <th>Срок</th>
                        <th>Статус</th>
                    </tr>
                    </thead>
                    <tbody>
                    {reportItems.map((item, index) => {
                        const isExpired = new Date(item.expiry) < today;
                        return (
                            <tr key={index} className={isExpired ? 'expired' : 'warning'}>
                                <td><b>{item.roomId}</b></td>
                                <td>{item.icon} {item.name}</td>
                                <td>{item.expiry}</td>
                                <td style={{fontSize: '10px', fontWeight: 'bold'}}>
                                    {isExpired ? 'ПРОСРОЧЕНО' : 'ЗАМЕНИТЬ'}
                                </td>
                            </tr>
                        );
                    })}
                    </tbody>
                </table>
                {reportItems.length === 0 && <p style={{marginTop: '30px', color: '#999'}}>Критичных сроков нет</p>}
            </div>
        </div>
    );
};

export default ExpiryList;
